105:  zbug_sentinel
109:    ZBUG_LINK_FRAG="${ZBUG_L}${z_text}${ZBUG_R} <${z_url}>"
111:    ZBUG_LINK_FRAG="${ZBUG_L}\033]8;;${z_url}\033\\\\${z_text}\033]8;;\033\\\\${ZBUG_R}"
118:bug_section() { zbug_sentinel; printf '%b\n' "${ZBUG_S}${1}${ZBUG_R}" >&2; }
119:bug_e()       { echo "" >&2; }
128:bug_c()       { zbug_show "${ZBUG_C}${1}${ZBUG_R}"; }
129:bug_E()       { zbug_show "${ZBUG_E}${1}${ZBUG_R}"; }
130:bug_t()       { zbug_show "${1}"; }
