132:bug_W()       { zbug_show "${ZBUG_W}${1}${ZBUG_R}"; }
135:bug_ct()      { zbug_show "${ZBUG_C}${1}${ZBUG_R}${2}"; }
136:bug_tc()      { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}"; }
137:bug_tE()      { zbug_show "${1}${ZBUG_E}${2}${ZBUG_R}"; }
138:bug_tu()      { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}"; }
139:bug_tW()      { zbug_show "${1}${ZBUG_W}${2}${ZBUG_R}"; }
140:bug_ut()      { zbug_show "${ZBUG_U}${1}${ZBUG_R}${2}"; }
143:bug_tct()     { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${3}"; }
144:bug_tcu()     { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${ZBUG_U}${3}${ZBUG_R}"; }
145:bug_tEt()     { zbug_show "${1}${ZBUG_E}${2}${ZBUG_R}${3}"; }
146:bug_tuc()     { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${ZBUG_C}${3}${ZBUG_R}"; }
147:bug_tut()     { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${3}"; }
148:bug_tWt()     { zbug_show "${1}${ZBUG_W}${2}${ZBUG_R}${3}"; }
151:bug_tctc()    { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${3}${ZBUG_C}${4}${ZBUG_R}"; }
152:bug_tctu()    { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${3}${ZBUG_U}${4}${ZBUG_R}"; }
153:bug_tcut()    { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${ZBUG_U}${3}${ZBUG_R}${4}"; }
154:bug_tuct()    { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${ZBUG_C}${3}${ZBUG_R}${4}"; }
155:bug_tutE()    { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${3}${ZBUG_E}${4}${ZBUG_R}"; }
156:bug_tutu()    { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${3}${ZBUG_U}${4}${ZBUG_R}"; }
159:bug_tctct()   { zbug_show "${1}${ZBUG_C}${2}${ZBUG_R}${3}${ZBUG_C}${4}${ZBUG_R}${5}"; }
160:bug_tutut()   { zbug_show "${1}${ZBUG_U}${2}${ZBUG_R}${3}${ZBUG_U}${4}${ZBUG_R}${5}"; }
165:# bug_link "prefix text" "link text" "url" "suffix text"
168:bug_link() {
169:  zbug_sentinel
181:      "${z_prefix}" "${z_link_style}" "${z_text}" "${ZBUG_R}" "${z_url}" "${z_suffix}" >&2
185:      "${z_prefix}" "${z_link_style}" "${z_url}" "${z_text}" "${ZBUG_R}" "${z_suffix}" >&2
195:# Arg mapping example for bug_tlt:
196:#   bug_tlt  "A "  "hallmark"  "https://...#hallmark"  " is a named artifact."
200:bug_lt()      { zbug_link_fragment "${1}" "${2}"; zbug_show "${ZBUG_LINK_FRAG}${3}"; }
201:bug_tl()      { zbug_link_fragment "${2}" "${3}"; zbug_show "${1}${ZBUG_LINK_FRAG}"; }
202:bug_tlt()     { zbug_link_fragment "${2}" "${3}"; zbug_show "${1}${ZBUG_LINK_FRAG}${4}"; }
203:bug_tlc()     { zbug_link_fragment "${2}" "${3}"; zbug_show "${1}${ZBUG_LINK_FRAG}${ZBUG_C}${4}${ZBUG_R}"; }
205:bug_tltlt() {
206:  zbug_link_fragment "${2}" "${3}"
207:  local -r z_frag1="${ZBUG_LINK_FRAG}"
208:  zbug_link_fragment "${5}" "${6}"
209:  zbug_show "${1}${z_frag1}${4}${ZBUG_LINK_FRAG}${7}"
215:# Sets ZBUG_TT_FRAG to a resolved tabtarget path in cyan for embedding
219:zbug_tabtarget_fragment() {
220:  zbug_sentinel
222:  test -e "${z_matches[0]}" || buc_die "bug: no tabtarget for colophon '${1}'"
223:  ZBUG_TT_FRAG="${ZBUG_C}${z_matches[0]}${ZBUG_R}"
232:bug_T()       { zbug_tabtarget_fragment "${1}"; zbug_show "${ZBUG_TT_FRAG}"; }
233:bug_tT()      { zbug_tabtarget_fragment "${2}"; zbug_show "${1}${ZBUG_TT_FRAG}"; }
234:bug_cT()      { zbug_tabtarget_fragment "${2}"; zbug_show "${ZBUG_C}${1}${ZBUG_R}${ZBUG_TT_FRAG}"; }
235:bug_tlT()     { zbug_link_fragment "${2}" "${3}"; zbug_tabtarget_fragment "${4}"; zbug_show "${1}${ZBUG_LINK_FRAG} ${ZBUG_TT_FRAG}"; }
236:bug_tltT()    { zbug_link_fragment "${2}" "${3}"; zbug_tabtarget_fragment "${5}"; zbug_show "${1}${ZBUG_LINK_FRAG}${4}${ZBUG_TT_FRAG}"; }
241:# bug_prompt "prompt text"
243:bug_prompt() {
244:  zbug_sentinel
251:# bug_prompt_required "prompt text" "error message"
252:# Like bug_prompt but dies if input is empty
253:bug_prompt_required() {
255:  z_input=$(bug_prompt "${1:-}")
257:    zbug_show "${ZBUG_E}ERROR:${ZBUG_R} ${2:-Input required}"
266:bug_critical() {
267:  zbug_sentinel
268:  zbug_show ""
269:  zbug_show "${ZBUG_E}===============================================${ZBUG_R}"
270:  zbug_show "${ZBUG_E}  CRITICAL: ${1}${ZBUG_R}"
271:  zbug_show "${ZBUG_E}===============================================${ZBUG_R}"
272:  zbug_show ""

